"""
MKT Context Commentary — Psalms chapters 68–70
Run: python3 scripts/zc-context-psalms-68-70.py

Key decisions in this range:
- Ps 68 is the hardest psalm in the Psalter (~20 hapax legomena); context focused on
  reconstructible ANE background, processional structure, and Sinai/theophany traditions
- ʿōlēb bāʿărābôt (rider on the clouds/heavens, v4): Ugaritic Baal epithet claimed for YHWH
- Ps 68:18 NT use in Eph 4:8 noted (Paul's inversion of 'received'→'gave' and its context)
- Ps 69 is the second most NT-cited passion psalm; all major NT citations noted at relevant verses
- The gall-and-vinegar (v21) and desolate-camp (v25) and let-their-table (vv22-23) fulfillments handled at the verse
- Ps 70 as doublet of Ps 40:13-17 noted; hazkir superscription explained
- Imprecatory sections (Ps 69:22-28) treated with honest acknowledgment of their hermeneutical
  difficulty; the NT's selective use is noted
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "68": {
    "1": '<p>Psalm 68 is widely regarded as the most difficult psalm in the Psalter — approximately 20 words appear nowhere else in the Hebrew Bible (<em>hapax legomena</em>), and many verses remain textually uncertain. Its superscription "A Psalm of David. A Song" suggests a combination of genres. The opening "Let God arise, let his enemies be scattered" is a direct quotation of Num 10:35 — the battle cry that was shouted when the ark moved forward through the wilderness. This verbal echo frames the entire psalm as a second Sinai-to-Zion processional: YHWH marches again, as he marched with Israel in the wilderness, now into his sanctuary on Zion.</p>',
    "2": '<p>"As smoke is dispersed by the wind... as wax melts before fire" — two destruction similes applied to the enemies of God. The smoke image recurs in Ps 37:20. The melting wax before fire appears in Ps 97:5 (theophany context) and Mic 1:4 (divine judgment). These images echo the Sinai theophany — smoke and fire were the sensory signatures of divine presence (Exod 19:18). The enemies\' dissolution before God\'s presence recalls the Egyptians at the sea (Exod 15:14-16: "Terror and dread fall on them; by the power of your arm they are silent as stone").</p>',
    "3": '<p>"Let the righteous be glad and rejoice before God; let them celebrate with great joy" — the contrast with v. 2 is sharp. The same divine presence that destroys the wicked exhilarates the righteous. "Before God (<em>lipnê ʾĕlōhîm</em>)" suggests cultic celebration in the sanctuary — the joy of access to the divine presence. This alternation of threat and celebration mirrors the Sinai experience: the people trembled at the mountain (Exod 20:18-19) while Moses and the elders "ate and drank in the presence of God" (Exod 24:11).</p>',
    "4": '<p>"Exalt him who rides upon the heavens" — the divine epithet <em>ʿōlēb bāʿărābôt</em> (rider upon the steppes/clouds/heavens) is a direct claim against Canaanite religion. In Ugaritic myth, Baal is called <em>rkb ʿrpt</em> (rider of the clouds) — the storm-god whose chariot rides through the sky. Israel\'s polemic: YHWH, not Baal, rides the heavens; YHWH, not Baal, sends rain and controls the storm. By using this title, Ps 68 makes an exclusive territorial claim: the atmospheric powers that Canaan attributed to Baal belong to YHWH alone. See also Ps 18:10; Deut 33:26.</p>',
    "5": '<p>"God in his holy dwelling is a father to the fatherless and a defender of widows" — the care for the marginalized is a standard attribute of the righteous king in ANE royal ideology. The preamble to the Code of Hammurabi (c. 1754 BCE) presents Hammurabi as the protector of widows and orphans, the champion of the weak against the strong. Israel claimed this royal social function exclusively for YHWH — the divine king who surpasses all human kings in justice toward the vulnerable. The combination of cosmic sovereignty (v. 4) and social protection (v. 5) is the Psalter\'s characteristic portrait of YHWH\'s kingship.</p>',
    "6": '<p>"God gives the isolated a home to belong to; he brings prisoners out into freedom; but the rebellious must live in a parched land" — three reversals. (1) The isolated (<em>yĕḥîdîm</em> — solitary, without family) given a household: the deepest social alienation — to lack kin in an honor-shame culture — is addressed by divine provision of belonging. (2) Prisoners brought into freedom (<em>kôšārôt</em> — prosperity, freedom) — the Exodus as paradigm. (3) The rebellious in a parched land — covenantal reversal: the land that should flourish under divine blessing becomes arid for those who reject the covenant.</p>',
    "7": '<p>"O God, when you went out before your people, when you marched through the wilderness — Selah" — the poem now moves into the great rehearsal of the wilderness march (vv. 7-10). The language echoes the oldest poetry in the Hebrew Bible: Deborah\'s Song (Judg 5:4-5) and the Blessing of Moses (Deut 33:2-5). "When you went out before your people (<em>bĕṣēʾtkā liphĕnê ʿammêkā</em>)" frames the Exodus as a military procession, with YHWH as the vanguard commander. <em>Selah</em> invites the congregation to pause and absorb this historical summation before the theophany description continues.</p>',
    "8": '<p>"The earth shook and the heavens poured down rain at the presence of God — even Sinai itself trembled — at the presence of the God of Israel" — the Sinai theophany described in terms of cosmic earthquake and storm. Exod 19:16-18 describes thunder, lightning, thick cloud, and smoke as YHWH descended on the mountain. Judg 5:4-5 ("The earth quaked, the heavens poured... the mountains quaked before the LORD") is the closest verbal parallel. The cosmic response to the divine march (earth shaking, rain falling) demonstrates that the entire creation is subject to YHWH — including the weather systems attributed to Baal.</p>',
    "9": '<p>"You sent an abundant rain (<em>gešem nĕdābôt</em>), O God; you restored your weary inheritance" — the rain that follows the divine march is both literal (the wilderness becomes fertile at divine command) and covenantal (the land as God\'s inheritance, <em>naḥălāh</em>). The "weary inheritance" (<em>naḥălātĕkā wĕnilĕʾāh</em>) may refer to Israel exhausted by wilderness wandering, or to the land itself depleted and dry. <em>Nĕdābôt</em> (voluntary, freewill, abundant) suggests that the rain exceeds what was asked — a grace beyond necessity.</p>',
    "10": '<p>"Your congregation settled in the land; in your goodness, O God, you provided for the needy (<em>ʾānî</em>)" — the settlement language (<em>yāšĕbû</em>) marks the transition from wilderness wandering to the gift of the land. "In your goodness" (<em>bĕṭûbātĕkā</em>) — divine provision is grounded in God\'s essential goodness, not human merit. The needy (<em>ʿānî</em>) as the recipients of the land\'s provision recalls the Levitical jubilee provisions in Lev 25 — the covenant economy designed to protect the vulnerable from permanent dispossession.</p>',
    "11": '<p>"The Lord gave the word; great was the army of women who announced the victory (<em>mĕbaśśĕrôt</em>)" — the heralds of divine victory are women in this verse. <em>Mĕbaśśĕrôt</em> (feminine plural of the verb to bring good news, the root of "gospel") echoes Exod 15:20-21, where Miriam and the women sang the victory song after the sea crossing. In Judg 5, Deborah and Jael are central to the victory. The great army of female announcers suggests a celebratory procession of women with tambourines (cf. v. 25; Judg 11:34; 1 Sam 18:6-7), the traditional form for announcing military victory.</p>',
    "12": '<p>"The kings of armies fled in haste; she who stayed at home shared in the plunder" — the picture of total victory: the enemy commanders flee so quickly that even those who stayed in camp (women, non-combatants) receive a share of the plunder. This motif appears in Deborah\'s Song (Judg 5:28-30, where Sisera\'s mother awaits plunder that never comes) and in the Jericho narrative (Josh 6) where the entire city\'s wealth goes to YHWH\'s treasury. The sociological reality: in ANE warfare, non-combatants who stayed behind expected their share of victory goods.</p>',
    "13": '<p>"Even if you once lay among the sheepfolds, you shall shine like the wings of a dove, silver-covered" — one of the most obscure verses in the psalm. "Lying among the sheepfolds (<em>šĕpattayim</em>)" may describe a state of inactivity or lowliness before the victory. The dove with silver wings and golden-yellow feathers may be a battle trophy (the ornamented wings of a captured dove?), a reference to Israelite women adorned with plunder, or a symbolic image of transformation from dullness to radiance. The image of transformation through divine victory — from sheep-pen dull to silver-and-gold gleam — is the central movement.</p>',
    "14": '<p>"When the Almighty scattered kings throughout the land, snow fell on Zalmon" — Zalmon is likely a mountain near Shechem (Judg 9:48), though exact identification is uncertain. The image of snow whitening the dark mountain after the enemy kings are scattered evokes the sudden reversal of a battle — the battlefield turning white after divine victory. "The Almighty" (<em>šadday</em>) is the archaic divine name associated with the patriarchal narratives (Gen 17:1; 28:3; Exod 6:3) — its use here gives the victory an ancient, primordial quality.</p>',
    "15": '<p>"The mountain of God is like the mountain of Bashan — a high, many-peaked mountain" — Bashan (the modern Golan Heights/Hauran region) was famous for its impressive volcanic peaks, particularly Mount Hermon (2,814m). The "mountain of God" in context is Mount Zion — geographically modest (only ~765m) but chosen by divine election. The contrast between the physically imposing Bashan mountains and the divinely chosen Zion mountain is the theological point: YHWH\'s choice, not topographical majesty, determines the sacred center.</p>',
    "16": '<p>"Why do you look with envy (<em>tĕraṣṣĕdûn</em>), O many-peaked mountains? This is the mountain that God chose for his dwelling place; the LORD will dwell there forever" — the mountains of Bashan are personified as envious of Zion. <em>Tĕraṣṣĕdûn</em> (look with envy, lie in wait) suggests hostile surveillance. The theological claim is audacious: the physically impressive mountains of the north are jealous of the small hill in Judah that YHWH chose. Divine election, not natural magnificence, defines sacredness. This theme runs through the prophets (Isa 2:2 — "the mountain of the LORD\'s temple will be established as the highest mountain").</p>',
    "17": '<p>"The chariots of God number in the tens of thousands, thousands upon thousands; the Lord is among them — as at Sinai, in his holy place" — the divine war host. ANE battle accounts counted chariots as the measure of military supremacy (Egypt\'s 600 chariots in Exod 14:7 was a terrifying force). YHWH\'s chariots are innumerable. The comparison "as at Sinai" connects the Zion procession to the original Sinai theophany — the same God who appeared at Sinai with his heavenly host now enters his Jerusalem temple with the same overwhelming force. Elijah would later see these chariots (2 Kgs 6:17).</p>',
    "18": '<p>"You have ascended to the heights, leading a train of captives; you have received tribute from men — even from the rebellious — so that the LORD God might dwell there" — this verse is cited by Paul in Eph 4:8, but with a significant modification: Paul writes "he gave gifts to men" instead of "received gifts/tribute from men." Scholarly explanations include: (1) Paul following a Targum tradition that already had "gave"; (2) Paul reading the psalm\'s movement (YHWH ascends and then distributes his captured wealth to his people) as a typological pattern for Christ\'s ascension and gift of the Spirit; (3) the psalm\'s own logic — tribute received is then distributed as the victor\'s largesse. Paul applies the ascension-and-distribution pattern to Christ.</p>',
    "19": '<p>"Blessed be the Lord, who day after day carries our burdens for us — the God of our salvation. Selah" — a benediction following the processional account. "Who day after day carries our burdens (<em>yaʿămas-lānû hāʾēl yĕšûʿātēnû</em>)" — the image of YHWH as the burden-bearer who shoulders the weight of his people\'s daily life, not only in great historical acts. This verse operates at both the cosmic scale (the preceding vv. 7-18) and the daily personal scale — the same God who marched with Israel through the wilderness carries each person\'s load each day. <em>Selah</em> invites reflection on this transition.</p>',
    "20": '<p>"Our God is the God of deliverance; and to the LORD, the Lord, belong the ways of escape from death" — <em>ʾēl lānû ʾēl lĕmôšāʿôt</em> (God to us is a God of deliverances, plural). The plural "deliverances" signals that divine rescue is not a single event but a pattern, a characteristic of YHWH\'s nature. "The ways of escape from death (<em>tôṣāʾôt lammāwet</em>)" — literally, the exits from death; the paths of escape from the realm of death. The covenantal claim: if YHWH controls even the exits from death, no threat is ultimately beyond his reach to rescue his people from.</p>',
    "21": '<p>"But God will crush the head of his enemies, the proud skull of those who persist in their guilt" — crushing the head recalls Gen 3:15 (the enmity between the seed of the woman and the serpent: "he will crush your head"). In ANE victory iconography, the conquered enemy king was depicted prostrate with the victorious king\'s foot on his head, crushing the skull — a standard posture of total domination. The "proud skull" (<em>qāḏqōḏ</em>) of the one who persists in guilt (<em>ʾašmāt</em>) — continued covenant violation — makes the defeat self-caused: persistent wickedness eventually meets its own crushing.</p>',
    "22": '<p>"The Lord declared, \'I will bring them back from Bashan; I will bring my people back from the depths of the sea\'" — the reversal promises. Bashan was known as a place of exile and distance (cf. Amos 4:1 — "you cows of Bashan"). The depths of the sea (<em>mimmĕṣulôt yām</em>) echoes the Reed Sea — the cosmic waters of chaos and the historical waters of the Exodus. YHWH will pursue his enemies even to Bashan\'s heights and the sea\'s depths — no geographic barrier limits his power to pursue judgment or rescue. The scope of divine sovereignty is total.</p>',
    "23": '<p>"So that your foot will be stained in the blood of your enemies, and the tongues of your dogs will lap it up" — the graphic imagery of total military victory. In ANE battle accounts, the complete slaughter of enemies was expressed through the image of blood so abundant that animals lapped it. This hyperbolic language (cf. Judg 5:30; Isa 63:1-6; Rev 14:20) was conventional in ancient military rhetoric — its purpose is to express the totality of divine justice, not to normalize blood-drinking. The dogs feasting on enemy blood recalls 1 Kgs 21:19 (Elijah\'s word against Ahab) — a marker of shameful death without burial.</p>',
    "24": '<p>"People have witnessed your procession, O God — the procession of my God, my King, into the holy place" — the processional scene now depicted as it is seen: a cultic procession into the temple, reenacting (or celebrating) the divine victory march. In Second Temple Judaism, such processionals were liturgical events with real participants — priests, Levites, ark, instruments. The entry of the ark into Jerusalem under David (2 Sam 6) is the historical prototype. The psalm has been moving from the cosmic march (vv. 7-18) to its cultic reenactment (vv. 24-27) — the temple liturgy as the present embodiment of the historical theophany.</p>',
    "25": '<p>"The singers lead the procession; behind them come the musicians; among them, young women playing tambourines (<em>ʿălāmôt tôpēpôt</em>)" — the order of the sacred procession: singers first (the choir), then instrumentalists (<em>nōgĕnîm</em>), then young women with tambourines (<em>tōpôt</em>). This matches the victory procession in Exod 15:20-21 (Miriam and women with tambourines) and the processional psalm tradition (Ps 150:4). The three-part musical ensemble was the standard festive processional format for major celebrations. Young women playing tambourines in public was a recognized cultural role for celebrating military and cultic victories.</p>',
    "26": '<p>"Bless God in the great assembly (<em>bĕmaqqĕhēlôt</em>); praise the LORD, all you who come from the fountain of Israel (<em>mimmeqôr yiśrāʾēl</em>)" — the invitation to the entire covenant community. "Fountain of Israel" — possibly refers to Jacob (Gen 49:24, "the Shepherd, the Rock of Israel") or to the patriarchal covenant as the source of the nation. The "great assembly" was the technical term for the full gathered congregation of Israel — the formal covenant assembly. To bless God "in the great assembly" is to perform the public, official act of covenant praise.</p>',
    "27": '<p>"There is Benjamin, the youngest, leading the way; the princes of Judah in their bright company; the princes of Zebulun, the princes of Naphtali" — four tribes representing the whole nation, but in a theologically loaded order. Benjamin is the smallest and youngest tribe, placed first — divine reversal (the least leads). Judah next — the royal tribe, the Davidic dynasty. Zebulun and Naphtali are northern tribes, the regions later celebrated in Isa 9:1-2 as "the land of darkness" that would see a great light. The ecumenical tribal representation signals national unity in worship before the divine king.</p>',
    "28": '<p>"Your God has established your power (<em>ʿuzzĕkā</em>); show your strength, O God, in what you have already begun for us" — the petition draws on what God has already done as the basis for what he is asked to continue. ANE petitions to deities frequently cited the deity\'s past benefactions as leverage for present requests. In Israelite theology this becomes: your past faithfulness is the grounds for our appeal for continued faithfulness. The divine track record of Exodus and conquest provides the basis for present petition.</p>',
    "29": '<p>"Because of your temple in Jerusalem, kings will bring their gifts (<em>yôbîlû mĕlāḵîm šay</em>) to you" — the eschatological vision: foreign kings bringing tribute to YHWH\'s temple in Jerusalem. This is the Zion pilgrimage theology developed by Isaiah: "Nations will come to your light and kings to the brightness of your rising" (Isa 60:3). The gift-bringing kings appear in Isa 60:5-7, 10-11 and Ps 72:10-11. In Second Temple Judaism, this expectation shaped the interpretation of the Magi\'s visit in Matt 2:1-12 — Gentile wise men bringing gifts to the divine king in Jerusalem.</p>',
    "30": '<p>"Rebuke the beast that lurks in the reeds (<em>ḥayyat qāneh</em>), the herd of bulls among the peoples\' young" — the beast in the reeds is Egypt. The Nile\'s reeds (<em>qāneh</em>) are the natural habitat of the hippopotamus and crocodile — both symbols of Egyptian power in the prophets (Ezek 29:3-5 — Egypt as the great dragon in the Nile; Isa 30:7 — Egypt is Rahab, a chaos monster). Calling Egypt a beast among reeds is a coded political reference. The petition is for YHWH to rebuke Egypt\'s power over the nations.</p>',
    "31": '<p>"Envoys will come from Egypt (<em>minnî miṣrāyim</em>); Ethiopia (<em>kûš</em>) will quickly extend her hands to God" — the eschatological reversal: Egypt, the archetypal oppressor, sends tribute; Ethiopia, the land at the ends of the known world (to Israel\'s south), stretches out hands in worship. This is the ultimate expansion of the Exodus pattern — not just Israel released from Egypt but Egypt itself turning to YHWH. The universal dimension: the two great Nile-valley powers represent the known world\'s submission. Isaiah 19:19-25 develops this vision explicitly (Egypt, Assyria, and Israel as three equal peoples of God).</p>',
    "32": '<p>"Sing to God, O kingdoms of the earth; sing praises to the Lord. Selah" — the summons broadens from Israel (vv. 24-27) to the tribes (v. 27) to the Gentile nations (v. 31) and now to all kingdoms. The universalization of Sinai worship is the theological trajectory of the whole psalm: what began as a battle cry before the ark becomes a worldwide invitation to praise. <em>Selah</em> marks this climactic expansion — the congregation pauses to absorb that the God who marched from Sinai is the God of all kingdoms.</p>',
    "33": '<p>"To him who rides upon the ancient heavens (<em>šĕmê šĕmê-qedem</em> — heavens of the primordial heavens/east)" — a superlative: the highest, oldest heavens, the primordial realm. "Listen, he thunders with his mighty voice" — the storm-theophany tradition: divine speech as thunder (cf. Job 37:5; Ps 29:3-9). In the ANE cosmological framework, the heavens above the visible sky were the realm of the divine council. YHWH\'s voice penetrating from there to earth is the ultimate demonstration of his sovereign speech-power over creation.</p>',
    "34": '<p>"Ascribe power (<em>ʿōz</em>) to God; his splendor is over Israel, and his strength is in the heavens" — the double location of divine strength: "over Israel" (covenant relationship) and "in the heavens" (cosmic sovereignty). The call to "ascribe" (<em>tĕnû</em>) power does not mean God lacks power but that the act of acknowledging his power is itself worship — the community\'s verbal recognition of reality. This is the theology of Ps 29 (the psalm of the divine voice-in-the-storm), which also ends with a call to ascribe glory and power to YHWH.</p>',
    "35": '<p>"God is awe-inspiring (<em>nôrāʾ</em>) from his sanctuary; the God of Israel is the one who gives strength and power to his people. Blessed be God!" — the closing doxology. <em>Nôrāʾ</em> (awesome, fear-inducing) is the standard adjective for divine theophany (Exod 34:10; Deut 7:21; 10:17). The final movement brings together cosmic sovereignty (vv. 4, 33) and covenant care (vv. 5-6, 19) in a single benediction: the fearsome God of the nations is the one who gives strength to his particular people. The psalm closes exactly where it opened — with the divine warrior, but now worshipped rather than petitioned.</p>'
  },
  "69": {
    "1": '<p>Psalm 69 is the second most frequently cited OT psalm in the NT Passion narratives (after Ps 22). Like Ps 22, it begins with desperate suffering and moves through petition to praise, but unlike Ps 22 it contains a major imprecatory section (vv. 22-28) that the NT engages selectively. The superscription "To the tune of \'The Lilies\' (<em>šōšannîm</em>)" is the same as Ps 45 (the royal wedding song) — an unlikely pairing that may indicate a popular melody used for contrasting moods. "Save me, O God, for the waters have risen to my neck (<em>nepeš</em>)" — flood imagery for overwhelming distress (cf. Ps 18:4-5; 42:7; Lam 3:54). <em>Nepeš</em> is literally soul/life — the waters are at his throat.</p>',
    "2": '<p>"I am sinking in the deep mud (<em>yāwēn mĕṣûlāh</em>) — no place to stand" — <em>yāwēn</em> is mire, mud, the bog at the bottom of a cistern or pit (cf. Jer 38:6, 22 — Jeremiah literally sunk in mud in a cistern). "The depths of the waters" and "the current sweeps over me" extend the drowning metaphor. The inability to find a foothold (<em>mʾōmāḏ</em> — a standing place) is the core of the distress: complete vulnerability, nothing to stand on. The physical image captures the social and spiritual experience — all supports gone.</p>',
    "3": '<p>"I am exhausted from calling out; my throat is raw; my eyes have given out while waiting for my God" — the physiology of prolonged prayer under duress. The raw throat from sustained crying is the physical mark of urgent petition. "Eyes given out" — the dimming of eyes signals approaching death in Hebrew medical thought (Ps 13:3; 1 Sam 14:27-29). The phrase "waiting for my God (<em>yiḥaltî lêʾlōhāy</em>)" contains the same root as "hope" (<em>yāḥal</em>): waiting with expectation, a hope that is wearing the person out by how long it is taking.</p>',
    "4": '<p>"Those who hate me without cause (<em>śōnĕʾay ḥinnām</em>) outnumber the hairs of my head" — the hyperbolic enumeration of enemies emphasizes their overwhelming number. "Without cause" (<em>ḥinnām</em>) is the crucial phrase — the psalmist is suffering unjustly, without having provoked the hatred. This phrase is cited in John 15:25 as fulfilled in the hatred directed at Jesus: "This is to fulfill what is written in their Law: \'They hated me without reason.\'" The application assumes that the "without cause" of the psalm points forward to the only person who perfectly merited no hatred at all — the sinless Christ.</p>',
    "5": '<p>"O God, you know my foolishness; and my sins are not concealed from you" — the transparency of the psalmist before God is notable. In a psalm that protests innocence from the enemies\' perspective (v. 4: "without cause"), the psalmist simultaneously acknowledges genuine failings to God. This is not a contradiction but a distinction: the psalmist has done nothing to deserve this particular suffering from these particular enemies, yet he is not sinless before God. The psalm holds together unjust human suffering and genuine human sinfulness.</p>',
    "6": '<p>"Let not those who hope in you be disgraced because of me, O Lord GOD of hosts; let not those who seek you be humiliated because of me, O God of Israel" — the communal dimension of personal crisis. In the honor-shame framework of ancient Israel, one person\'s public humiliation dishonored the entire community that identified with them. The psalmist prays that his suffering not become a scandal that deters others from trusting God — his disgrace should not become an argument against YHWH\'s faithfulness. The titles "Lord GOD of hosts" and "God of Israel" both invoke YHWH\'s covenant relationship as the basis for the petition.</p>',
    "7": '<p>"For your sake I have borne disgrace (<em>ḥerpāh</em>); humiliation has covered my face" — the social cost of covenant loyalty. <em>Ḥerpāh</em> (disgrace, reproach) is the most damaging thing that could happen in an honor-shame culture — the public stripping of one\'s social honor. "For your sake" (<em>ʿālêkā</em>) is the theological center of this and the following verses: the psalmist\'s suffering is suffered in YHWH\'s cause, not for personal wrongdoing. This pattern — suffering for God\'s cause that falls on the faithful servant — is the basis for the NT\'s application of Ps 69 to Christ.</p>',
    "8": '<p>"I have become a stranger to my brothers, an outsider to my own mother\'s children (<em>ʾezrāḥ libnê ʾimmî</em>)" — family estrangement as the deepest social rupture. In ancient Israel, the family unit (<em>bêt ʾāb</em>, father\'s house) was the primary social safety net — providing economic support, legal advocacy, and social identity. To be estranged from one\'s brothers and half-brothers was to lose all of these simultaneously. The phrase "mother\'s children" specifically — full brothers, not merely legal kin — emphasizes that even the closest blood relationships have broken. The NT applies this to Jesus\'s family\'s misunderstanding of his mission (John 7:5).</p>',
    "9": '<p>"Zeal for your house has consumed me; and the insults directed at you have landed on me" — the most directly cited verse of Ps 69 in the NT. John 2:17 records the disciples\' memory of this verse during the temple cleansing: "His disciples remembered that it is written: \'Zeal for your house will consume me.\'" Paul quotes the second half in Rom 15:3: "For even Christ did not please himself, but as it is written: \'The insults of those who insult you have fallen on me.\'" The double citation activates both halves: Jesus\'s fierce protective passion for the sanctity of God\'s house (consuming him toward the cross) and his bearing of insults that were directed at God.</p>',
    "10": '<p>"When I wept and humbled my soul with fasting, that became a source of shame for me" — fasting was the standard expression of mourning, penitence, and urgent petition in ancient Israel (Joel 1:14; Isa 58:3-7; Neh 1:4). To fast publicly was to make a visible statement of humility and need. But when fasting becomes "a source of shame" — when the very act of religious devotion is turned into mockery — the social collapse is complete. The person who mourns over the state of the temple (v. 9) and practices the covenant disciplines is held up to ridicule by those who should honor such practices.</p>',
    "11": '<p>"I dressed in sackcloth, and I became a laughingstock (<em>māšāl</em>) to them" — sackcloth was the garment of mourning and penitence, worn close to the skin (1 Kgs 21:27; 2 Kgs 6:30; Isa 32:11). It was rough, scratchy, dark-colored — a deliberate physical discomfort signaling inner distress. <em>Māšāl</em> means both "parable" and "mockery/byword" — to become a byword is to become a representative example, a proverb of disgrace. The social reversal: practices meant to signal sincere piety (fasting, sackcloth) are read by the mockers as evidence of weakness or failure rather than covenant devotion.</p>',
    "12": '<p>"Those who sit at the city gate gossip about me; and I have become the subject of the drunkards\' songs" — two social settings. (1) The city gate (<em>šaʿar</em>) was the civic center: courts, commerce, formal social transactions (Ruth 4:1-11; Prov 31:23). The "elders sitting at the gate" were the respectable community leaders. To be the subject of their gossip was maximum social exposure at maximum social altitude. (2) "Drunkards\' songs" (<em>šōtê šēkār</em>) — the disreputable end of society mocking him. Both ends of the social spectrum have joined in contempt.</p>',
    "13": '<p>"But as for me, my prayer is directed to you, LORD, at a time of your favor (<em>ʿēt rāṣôn</em>); O God, in your great steadfast love (<em>ḥeseḏ</em>), answer me with your certain salvation (<em>ʾĕmet yišʿĕkā</em>)" — the pivot from social description to prayer. "A time of your favor" (<em>ʿēt rāṣôn</em>) is a key term in the theology of acceptable sacrifice and prayer (Isa 49:8; 56:7; 2 Cor 6:2 — Paul applies this to the present age of gospel proclamation). The petition is grounded in three divine attributes: <em>ḥeseḏ</em> (covenantal loyalty), <em>ʾĕmet</em> (faithfulness/truth), and <em>yeša</em> (salvation) — the triple foundation of covenant relationship.</p>',
    "14": '<p>"Rescue me from the mire (<em>ṭîṭ</em>) and do not let me sink" — the return to the mud/mire imagery of v. 2 ties the petition directly to the description of distress. <em>Ṭîṭ</em> is wet clay or mud — a cistern floor (Jer 38:22 uses the same word for the mud where Jeremiah was sunk). "From those who hate me and from the deep waters" — the enemies and the cosmic chaos-waters are parallel threats, both requiring divine rescue. The psalmist is caught between social threat (those who hate) and cosmic threat (the deep) — the petition addresses both simultaneously.</p>',
    "15": '<p>"Let not the flood sweep me away; let not the depths (<em>mĕṣûlāh</em>) swallow me; let not the pit (<em>bĕʾēr</em>) close its mouth on me" — three escalating images of total engulfment. The flood sweeping away, the depths swallowing, the pit closing its mouth — each is an image of cosmic consumption that leaves no trace. The "pit closing its mouth" personifies Sheol as a mouth that opens to receive the dead and then closes permanently (cf. Num 16:30-33; Isa 5:14 — Sheol "opens its mouth wide"). The three parallel petitions form a rhetorical intensification: do not let any of these three forms of total loss happen to me.</p>',
    "16": '<p>"Hear me, LORD, for your steadfast love (<em>ḥeseḏ</em>) is good; in your great compassion (<em>rōb raḥămêkā</em>), turn toward me" — the double motivation for divine attention: <em>ḥeseḏ</em> (covenant loyalty, goodness) and <em>raḥămîm</em> (deep compassion, womb-love). <em>Raḥămîm</em> derives from the same root as <em>reḥem</em> (womb) — the gut-level compassion of a mother for her child. This is the most intimate of the divine attributes in the Hebrew theological vocabulary. "Turn toward me (<em>pĕnēh-ʾēlay</em>)" — the petition is literally for God to face him: to turn his face back toward the psalmist after the apparent turning-away of vv. 1-15.</p>',
    "17": '<p>"Do not turn your face away from your servant; I am in great distress — answer me quickly" — the urgency of "answer me quickly (<em>maḥēr ʿănēnî</em>)" appears also in Ps 70:1, 5 (the abbreviated doublet) and Ps 143:7. The situation does not permit delay; divine response must come in time to matter. "Your servant (<em>ʿabdĕkā</em>)" is the standard covenantal self-designation before a sovereign — claiming the relationship that entitles one to the sovereign\'s attention and protection. The servant-sovereign relationship in ancient Israel was not mere metaphor but a defined covenantal structure with reciprocal obligations.</p>',
    "18": '<p>"Come near to my soul and rescue it (<em>qorbāh ʾel-napšî gĕʾālāh</em>); set me free because of my enemies" — the kinsman-redeemer language. <em>Gāʾal</em> (redeem/ransom) is the verb of the <em>gōʾēl</em> (kinsman-redeemer): the close relative who redeems a family member from debt-slavery, avengers blood, or protects widowed kin (Lev 25:25-28; Ruth 2:20; 3:12-13; 4:1-10). The petition asks YHWH to act as the ultimate kinsman-redeemer — to come close (<em>qārab</em>) and perform the redemptive act that only a close relative can perform. This theology of divine kinship is foundational to the NT\'s understanding of Christ as Redeemer.</p>',
    "19": '<p>"You know my disgrace, my shame, and my humiliation (<em>ḥerpātî ûbāšetî ûkĕlimmātî</em>); all my enemies are in your sight" — three words for social dishonor, a cascade of shame-vocabulary. <em>Ḥerpāh</em> (reproach/disgrace), <em>bōšet</em> (shame), <em>kĕlimmāh</em> (humiliation/dishonor) — each term slightly more intense than the previous. In the covenant legal framework, the psalmist is presenting his case to God, laying out the full extent of his social destruction. "All my enemies are in your sight" — the divine omniscience that the enemies deny (cf. Ps 10:11) is here invoked as the basis for justice: God sees what they are doing.</p>',
    "20": '<p>"Disgrace has broken my heart (<em>ḥerpāh šābrāh libbî</em>) so that I am in anguish; I looked for someone to show compassion (<em>lānûd</em>), but there was none" — "broken my heart" — the word-picture is of a shattered vessel, social humiliation that damages the person at their core. "Someone to show compassion" (<em>lānûd</em>) — the word means to nod in sympathy, to mourn with, to show physical solidarity (Job 2:11 — Job\'s friends came "to mourn with him and to comfort him"). No one came. The ultimate social isolation: not just enemies attacking but friends absent. This verse is the emotional center of the psalm — utter loneliness in suffering.</p>',
    "21": '<p>"They put bitter gall (<em>rōʾš</em>) in my food; and when I was thirsty, they offered me vinegar (<em>ḥōmeṣ</em>) to drink" — this verse is cited in the Passion narratives as fulfilled at the crucifixion. Matt 27:34 (wine mixed with gall offered before the crucifixion), John 19:28-30 (vinegar offered when Jesus says "I am thirsty"), and Mark 15:36 (vinegar on a sponge) all echo this verse. <em>Rōʾš</em> (gall/poison plant, possibly wormwood or hemlock) in food, and <em>ḥōmeṣ</em> (sour wine, vinegar) for thirst — the perversion of hospitality: offering toxic food and degrading drink rather than the bread and wine of covenant fellowship.</p>',
    "22": '<p>"Let their table be set as a snare (<em>šulḥānām</em>) before them; and what was meant for their prosperity become a trap" — the first of the imprecatory petitions (vv. 22-28). Paul quotes Ps 69:22-23 in Romans 11:9-10, applying it to Israel\'s failure to believe the gospel: the blessings of covenant (the table) become the occasion of stumbling when they are received without faith. The "table" (<em>šulḥān</em>) is the central covenant meal table — in Israel\'s theology, shared meals sealed relationships and created obligations of loyalty. The table becoming a snare is the conversion of covenant gift into covenant judgment.</p>',
    "23": '<p>"Let their eyes be darkened so they cannot see; and let their bodies tremble without ceasing" — Paul cites this verse immediately after v. 22 in Rom 11:9-10 to describe Israel\'s spiritual blindness to the Messiah. "Eyes darkened so they cannot see" becomes, in Paul\'s reading, the judicial hardening that falls on those who reject the covenant\'s fulfillment. In the psalm\'s original context, the darkening of eyes is both literal incapacitation (failing sight signals dying) and a divine judicial act — the reversal of the psalmist\'s experience (whose own eyes were "giving out" in v. 3 from watching for God).</p>',
    "24": '<p>"Pour out your wrath (<em>zaʿamĕkā</em>) upon them; let your fierce anger (<em>ḥărôn ʾappĕkā</em>) seize them" — the petition passes from individual consequences (vv. 22-23) to direct divine judgment. <em>Zaʿam</em> (wrath, indignation) and <em>ḥărôn ʾap</em> (fierce anger, literally the burning of the nostrils) are the two strongest terms for divine wrath in Hebrew. The imprecations (vv. 22-28) function as covenant curses — the other side of covenant blessing, which the psalmist rightly invokes against those who persecute God\'s servants. In NT appropriation, they become prophetic announcement of the judgment that falls on those who reject Christ.</p>',
    "25": '<p>"Let their camp become desolate; let no one live in their dwelling" — this verse is cited in Acts 1:20 by Peter in the context of replacing Judas: "For it is written in the Book of Psalms: \'Let his homestead become desolate; let no one live in it.\'" Peter applies the imprecation on those who persecuted God\'s servant directly to Judas, who betrayed the servant of servants. The "camp" (<em>ṭîrāh</em> — an encampment, a village of tents) becoming desolate is the reversal of the divine promise of peaceful habitation. The application in Acts assumes that the enemies of Christ are the ultimate fulfillment of those who persecuted the psalmist.</p>',
    "26": '<p>"For they have harassed (<em>rādāpû</em>) the one whom you have afflicted; they have gossiped about the suffering of those you wounded" — the theological indictment of the persecutors: they have compounded divine discipline with human cruelty. <em>Rādāpû</em> (persecuted, chased) is the verb of relentless pursuit. The psalmist is someone whom God himself has "afflicted" (permitted to suffer) — but the enemies have taken this divine permission as license to add their own cruelty and mockery. The sin is not inflicting pain on the psalmist per se but adding human malice to divine discipline.</p>',
    "27": '<p>"Pile their guilt on top of their guilt; and do not let them share in your vindication (<em>ṣiḏqātĕkā</em>)" — the petition asks that the enemies\' guilt accumulate without atonement. "Do not let them share in your vindication (<em>ṣedeq</em>)" — literally: do not let them enter into your righteousness. The covenant structure: those who attack God\'s servant place themselves outside the covenant order in which divine righteousness provides acquittal. The imprecation is not personal revenge but a call for the covenant\'s own logic to play out: persistent covenant violation excludes from covenant benefit.</p>',
    "28": '<p>"Let them be erased from the scroll of the living (<em>sēper ḥayyîm</em>); let them not be listed among the righteous" — the "scroll of the living" is an ANE concept (Mesopotamian "tablets of destiny"; Exod 32:32-33 where Moses asks to be blotted out; Dan 12:1; Rev 13:8; 20:12) — a divine register of those whose lives are secured. To be "erased from the scroll" is the permanent withdrawal of divine protection and life-grant. "Listed among the righteous (<em>ṣaddîqîm</em>)" — the covenant community of those in right standing with YHWH. The two parallel phrases together span both life and righteousness: the enemies lose both.</p>',
    "29": '<p>"But I am afflicted and in pain; may your salvation (<em>yišʿĕkā</em>), O God, lift me up" — the turn from imprecation back to personal petition. The sharp contrast (enemies lose their place in the book of life; the psalmist humbly asks to be lifted up) marks the end of the imprecatory section. "Afflicted and in pain" (<em>ʿānî wĕḵōʾēb</em>) — the same <em>ʿānî</em> vocabulary of poverty/humility that runs through the Psalms; "in pain" (<em>ḵōʾēb</em>) adds the specific experience of suffering. The psalmist\'s self-description is minimal: not claimed vindication but simple need.</p>',
    "30": '<p>"I will praise the name of God with a song of praise (<em>šîr</em>); I will honor him with thanksgiving (<em>tôdāh</em>)" — the sudden turn to praise. The vow of praise was a formal covenant commitment: in distress, the psalmist pledges that if God delivers, he will bring a formal thanksgiving offering (<em>tôdāh</em>) to the sanctuary. The thanksgiving offering was the primary peace offering in the Levitical system (Lev 7:12-15) — a communal meal before God celebrating his deliverance. The psalmist commits to public, liturgical gratitude rather than private relief.</p>',
    "31": '<p>"This will please the LORD more than an ox or a bull with its horns and hoofs" — the comparison of praise to sacrifice is a recurring prophetic-wisdom theme (Ps 40:6-8; 50:8-15; 51:16-17; Hos 6:6; Amos 5:21-24). The emphasis on "horns and hoofs" (<em>maqrîn maphris</em>) specifies a fully-grown, physically complete sacrifice — the best of the herd. The claim: the song of thanksgiving from a broken heart exceeds even the most costly animal sacrifice. This is not a rejection of the sacrificial system but a ranking: genuine praise from the delivered heart surpasses external performance without inward reality.</p>',
    "32": '<p>"The afflicted (<em>ʿănāwîm</em>) will see it and rejoice; those of you who seek God, may your hearts be renewed" — the community dimension: the psalmist\'s individual deliverance becomes an encouragement to the entire community of the <em>ʿănāwîm</em> (humble/afflicted). In Second Temple Judaism, the <em>ʿănāwîm</em> were not just the economically poor but the pious community of those who depended entirely on God. The public testimony of one person\'s deliverance strengthens the entire community\'s confidence in God\'s care (cf. Ps 22:24-31 for the same movement).</p>',
    "33": '<p>"For the LORD listens to the needy (<em>ʾebyônîm</em>); he does not look down on those he has bound (<em>ʾăsûrāyw</em>)" — divine attentiveness to the marginalized as a covenantal guarantee. "Those he has bound (<em>ʾăsûrāyw</em>)" — those in chains, the imprisoned. Cf. Ps 146:7 ("the LORD sets prisoners free") and Isa 61:1 ("to proclaim freedom for the captives"). In Jesus\'s programmatic reading of Isa 61:1 in Luke 4:18, this vocabulary becomes central to his self-understanding. The "bound" are those whom the wicked have physically or socially restrained — YHWH does not abandon them in their bondage.</p>',
    "34": '<p>"Let heaven and earth give him praise, the seas and every living thing in them" — the cosmic praise call echoes the structure of Ps 148 (where every tier of creation — heavenly beings, atmospheric phenomena, land creatures, sea creatures — is called to praise). The theology: the God who hears one afflicted psalmist is the same God to whom all creation owes worship. Personal and cosmic praise are not separate categories but parts of a single unified chorus. The Second Temple liturgy would have read vv. 32-34 as moving from the gathered community outward to the entire creation — the eschatological horizon of worship.</p>',
    "35": '<p>"For God will save Zion and rebuild the cities of Judah; people will live there and take possession of it" — a forward-looking promise with strong post-exilic resonance. The rebuilding of destroyed cities of Judah and the resettlement of the land was the great hope of the exilic and early post-exilic community (Jer 31:38-40; Ezek 36:10; Zech 1:17). In its Davidic-era context, this may have referred to the ongoing consolidation of the kingdom; in its post-exilic reading (the Psalter\'s final form), it points to restoration from Babylonian destruction. The specific mention of "cities of Judah" (plural) suggests the verse gained particular resonance after 587 BCE.</p>',
    "36": '<p>"The children of his servants will inherit it; and those who love his name will live there" — the inheritance promise passes through generations: the children of the servants inherit what their parents were promised but perhaps did not fully receive. "Those who love his name (<em>ʾōhăbê šĕmô</em>)" — covenant loyalty expressed as love for the divine name (cf. Ps 5:11; 119:132). The psalm ends with the community of the future — those yet to be born who will inhabit the restored land. The movement of the whole psalm: from individual drowning (v. 1) through communal suffering and petition, to the eschatological community that inherits the promised restoration.</p>'
  },
  "70": {
    "1": '<p>Psalm 70 is a doublet of Ps 40:13-17 — the final five verses of Ps 40 appear here as a standalone emergency prayer. The main differences: Ps 70 uses <em>Elohim</em> where Ps 40 uses <em>YHWH</em>, and Ps 70:5 reads slightly differently from Ps 40:17. The superscription "to bring to remembrance (<em>hazkîr</em>)" — also in Ps 38 — probably refers to the <em>azkārāh</em>, a memorial portion of grain offering (Lev 2:2, 9, 16) associated with prayer and remembrance before God. Liturgically, Ps 70 was likely used as a standalone petition of urgency — an abbreviated form of Ps 40 stripped to its essential plea, extracted for use in acute crisis. The echo data for this psalm notes connections to Heb 5:7 (Jesus\'s urgent prayer) and Matt 26:39 (Gethsemane).</p>',
    "2": '<p>"Let those who seek my life be put to shame and confusion; let those who delight in my harm be turned back and disgraced" — the defensive petition: the reversal of the attackers\' plans. "Shame and confusion (<em>yēbōšû wĕyaḥpĕrû</em>)" — both terms are honor-shame vocabulary: <em>bōš</em> (be ashamed, suffer disgrace) and <em>ḥāpar</em> (be ashamed, be in confusion). "Those who delight in my harm (<em>ḥāpēṣ rāʿātî</em>)" — enemies whose active pleasure is the psalmist\'s destruction, not merely incidental opposition. The prayer asks that their delight be converted into disgrace — the precise inversion of their intentions.</p>',
    "3": '<p>"Let them be turned back in their shame — those who say, \'Aha, aha! (<em>heʾāḥ heʾāḥ</em>)!\'" — the mocking exclamation <em>heʾāḥ</em> (aha! / ha ha!) is the verbal expression of schadenfreude — gloating at another\'s suffering. It appears in Pss 35:21, 25; 40:15; Ezek 25:3; 26:2 — always in the mouth of enemies who take pleasure in the fall of Israel or her king. The prayer is not merely that enemies fail but that those who gloated be specifically humiliated — turned back (<em>yāšûbû</em>) in the shame they wanted to impose on the psalmist. The mirror of justice: the emotion they expressed becomes their experience.</p>',
    "4": '<p>"But let all who seek you rejoice and be glad in you; let those who love your salvation say always, \'God is great (<em>yigdal ʾĕlōhîm</em>)!\'" — the communal positive petition contrasts sharply with vv. 2-3. Those who seek YHWH are invited into joy; those who love his salvation (<em>yĕšûʿāh</em>) are to perpetually proclaim his greatness. "God is great" (<em>yigdal ʾĕlōhîm</em>) — the continuous, perpetual (<em>tāmîd</em>) acclamation: an ongoing liturgical posture of acknowledging divine majesty. Paul echoes the spirit of this verse in Phil 4:4 ("Rejoice in the Lord always; I will say it again, rejoice!"), applying the same perpetual joy to the community of those who love God\'s salvation.</p>',
    "5": '<p>"But I am poor and needy (<em>ʿānî wĕʾebyôn</em>); hurry to me, O God! You are my help and my deliverer; O LORD, do not tarry (<em>ʾal-tĕʾaḥar</em>)" — the compressed closing verse brings together the standard self-designation of the Psalter\'s petitioner (<em>ʿānî wĕʾebyôn</em> — poor and needy; cf. Ps 40:17; 69:29; 86:1) with the most urgent petition of the psalm: "do not tarry." The urgency throughout Ps 70 is exceptional even for the lament genre — "hurry to deliver" (v. 1), "make haste to help" (v. 1), "hurry to me" (v. 5), "do not tarry" (v. 5). Time itself is the critical variable; divine delay is the specific fear. The psalm is the concentrated essence of crisis prayer.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    print('Psalms 68-70 mkt-context written.')

if __name__ == '__main__':
    main()
